#include <iostream>

int* buildSquares(int n)
{
    int* arr{ new int[n] };
    for (int i{ 0 }; i < n; ++i)
        arr[i] = (i + 1) * (i + 1);
    return arr;
}

int main()
{
    int n{};
    std::cin >> n;

    int* squares{ buildSquares(n) };

    for (int i{ 0 }; i < n; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << squares[i];
    }
    std::cout << '\n';

    delete[] squares;

    return 0;
}

