#include <iostream>

int main()
{
    int n{};
    std::cin >> n;

    int* arr{ new int[n] };
    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    int sum{ 0 };
    int min{ arr[0] };
    int max{ arr[0] };
    for (int i{ 0 }; i < n; ++i)
    {
        sum += arr[i];
        if (arr[i] < min)
            min = arr[i];
        if (arr[i] > max)
            max = arr[i];
    }

    std::cout << "sum: " << sum << '\n';
    std::cout << "min: " << min << '\n';
    std::cout << "max: " << max << '\n';

    delete[] arr;

    return 0;
}
